var e=[{id:`L2_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NEXT_NULL`,text:{KOREA:`어쩔 수 없네요. 형식상이라고는 해도 약속은 약속이니까, 평생 책임져 주시지 않으면 큰일날 거라구요?`,JPN:`仕方ないですね。形式的なものでも約束は約束ですから、一生責任取ってくれなかったら大変なことになりますよ？ `,ENG:`I guess there's no other option. Even if it's just a formality, a promise is a promise. So you better stick with me until the end, in sickness and in health.`,TWN:`沒辦法，雖然只是一個形式，但畢竟是契約就是契約，你如果沒有負我一輩子的責任就慘囉？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NEXT_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NEXT_NULL`,text:{KOREA:`아, 그러면 저도 사장님을 책임져야 하는 거죠…? 아, 아니. 딱히 그런 걸 의식하고 한 말은 아니라니까요?`,JPN:` あ、だったら私も社長に対して責任を取ることになりますよね……？　あ、いえ。特にそういうことを意識して言ったわけではなくてですね？`,ENG:`Oh, that means I'll have to stick with you, too... W-wait. I didn't mean it like that kind of thing.`,TWN:`那我是不是也要對老闆負責…？那…那個，我隨口說說的，沒別的意思！`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NEXT_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};